class ConnectedComponents {
    static func solve(_ arr: [Int]) -> [Int] {
        if arr.count < 2 { return [] }

        let n = arr[0]
        let m = arr[1]

        if arr.count < 2 + 2 * m { return [] }
        if n == 0 { return [] }

        var adj = [[Int]](repeating: [], count: n)
        for i in 0..<m {
            let u = arr[2 + 2 * i]
            let v = arr[2 + 2 * i + 1]
            if u >= 0 && u < n && v >= 0 && v < n {
                adj[u].append(v)
                adj[v].append(u)
            }
        }

        var labels = [Int](repeating: -1, count: n)
        var q = [Int]()

        for i in 0..<n {
            if labels[i] == -1 {
                let componentId = i
                labels[i] = componentId
                q.append(i)

                var head = 0
                while head < q.count {
                    let u = q[head]
                    head += 1

                    for v in adj[u] {
                        if labels[v] == -1 {
                            labels[v] = componentId
                            q.append(v)
                        }
                    }
                }
                q.removeAll()
            }
        }

        return labels
    }
}

export function connectedComponents(arr: number[]): number[] {
  if (arr.length < 2) {
    return [];
  }

  const n = arr[0];
  const m = arr[1];
  const adj: number[][] = Array.from({ length: n }, () => []);

  for (let i = 0; i < m; i += 1) {
    const u = arr[2 + 2 * i];
    const v = arr[2 + 2 * i + 1];
    adj[u].push(v);
    adj[v].push(u);
  }

  const labels = new Array(n).fill(-1);
  for (let start = 0; start < n; start += 1) {
    if (labels[start] !== -1) {
      continue;
    }

    const queue = [start];
    labels[start] = start;
    for (let head = 0; head < queue.length; head += 1) {
      const node = queue[head];
      for (const neighbor of adj[node]) {
        if (labels[neighbor] === -1) {
          labels[neighbor] = start;
          queue.push(neighbor);
        }
      }
    }
  }

  return labels;
}

export function connectedComponents(arr: number[]): number[] {
  if (arr.length < 2) return [];

  const n = arr[0];
  const m = arr[1];

  if (arr.length < 2 + 2 * m) return [];
  if (n === 0) return [];

  const adj: number[][] = Array.from({ length: n }, () => []);
  for (let i = 0; i < m; i++) {
    const u = arr[2 + 2 * i];
    const v = arr[2 + 2 * i + 1];
    if (u >= 0 && u < n && v >= 0 && v < n) {
      adj[u].push(v);
      adj[v].push(u);
    }
  }

  const labels: number[] = new Array(n).fill(-1);
  const q: number[] = [];

  for (let i = 0; i < n; i++) {
    if (labels[i] === -1) {
      const componentId = i;
      labels[i] = componentId;
      q.push(i);

      let head = 0;
      while (head < q.length) {
        const u = q[head++];

        for (const v of adj[u]) {
          if (labels[v] === -1) {
            labels[v] = componentId;
            q.push(v);
          }
        }
      }
      q.length = 0;
    }
  }

  return labels;
}
